{
  "Tags": [
    { "Key": "Environment", "Value": "production" },
    { "Key": "Team",        "Value": "platform-engineering" },
    { "Key": "Project",     "Value": "payments-api" },
    { "Key": "CostCenter",  "Value": "CC-1042" }
  ]
}
// Apply during creation or post-creation via "Manage tags" in any resource detail page.
// Cost Allocation Tags (enabled in Billing) let these keys appear in Cost Explorer.

# Enable IAM access to billing (run as root or via root session):
aws iam create-account-alias --account-alias mycompany   # optional, sets sign-in URL alias

# Enable IAM users to access billing information:
# Go to: Account Settings > IAM User and Role Access to Billing Information > Activate

# Create a billing alert via CLI (after enabling billing access for IAM):
aws budgets create-budget   --account-id "$(aws sts get-caller-identity --query Account --output text)"   --budget '{
    "BudgetName": "monthly-spend-alert",
    "BudgetLimit": { "Amount": "100", "Unit": "USD" },
    "TimeUnit": "MONTHLY",
    "BudgetType": "COST"
  }'   --notifications-with-subscribers '[{
    "Notification": {
      "NotificationType": "ACTUAL",
      "ComparisonOperator": "GREATER_THAN",
      "Threshold": 80,
      "ThresholdType": "PERCENTAGE"
    },
    "Subscribers": [{
      "SubscriptionType": "EMAIL",
      "Address": "billing-alerts@mycompany.com"
    }]
  }]'

{
  "Version": "2012-10-17",
  "Statement": [
    {
      "Effect": "Allow",
      "Principal": {
        "AWS": "arn:aws:iam::111122223333:root"
      },
      "Action": "sts:AssumeRole",
      "Condition": {
        "Bool": {
          "aws:MultiFactorAuthPresent": "true"
        }
      }
    }
  ]
}
// Trust policy on the target role in the production account (222233334444).
// Allows principals from the identity account (111122223333) to assume this role,
// but only if MFA was used — enforcing MFA on cross-account role switches.

{
  "source": ["aws.health"],
  "detail-type": ["AWS Health Event"],
  "detail": {
    "eventTypeCategory": ["scheduledChange"],
    "service": ["RDS", "ELASTICACHE"]
  }
}
// EventBridge pattern to catch PHD scheduled maintenance events for RDS and ElastiCache.
// Route this to an SNS topic and page the on-call team 2 weeks before the maintenance window.

{
  "Version": "2012-10-17",
  "Statement": [
    {
      "Sid": "DenyConsoleFromNonCorporateIP",
      "Effect": "Deny",
      "Action": "aws-portal:*",
      "Resource": "*",
      "Condition": {
        "NotIpAddress": {
          "aws:SourceIp": [
            "203.0.113.0/24",
            "198.51.100.0/24"
          ]
        }
      }
    }
  ]
}
// SCP that denies access to the Billing console from outside corporate IP ranges.
// Apply to the Billing OU or the management account OU.
// Note: aws-portal:* covers billing and cost management console pages.
